      const header = headers[columnIndex];
      rowObject[header] = coerceValue(fields[columnIndex] ?? '');
    }
    rows.push(rowObject);
  }

  if (unterminatedQuoteRow !== null) {
    errors.push({
      row: unterminatedQuoteRow,
      message: 'Unterminated quoted field detected.',
    });
  }

  const filter = (predicate: (row: CSVRow) => boolean): CSVRow[] => rows.filter(predicate);

  const sum = (column: string): number => {
    let total = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  };

  const average = (column: string): number | null => {
    let total = 0;
    let count = 0;

    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }

    if (count === 0) {
      return null;
    }

    return total / count;
  };

  const count = (): number => rows.length;

  const groupBy = (column: string): Map<any, CSVRow[]> => {
    const grouped = new Map<any, CSVRow[]>();
    for (const row of rows) {
      const key = row[column];
      if (!grouped.has(key)) {
        grouped.set(key, []);
      }
      grouped.get(key)!.push(row);
    }
    return grouped;
  };

  return {
    headers,
    rows,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy,
  };
}

import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const runTests = () => {
  // Basic parsing
  const basic = parseCSV('name,age\nAlice,30\nBob,25');
  assert(basic.headers.length === 2, 'Basic parsing - headers count');
  assert(basic.rows.length === 2, 'Basic parsing - row count');
  assert(basic.rows[0].name === 'Alice', 'Basic parsing - first row value');
  assert(basic.rows[0].age === 30, 'Basic parsing - type coercion int');
  assert(basic.errors.length === 0, 'Basic parsing - errors');

  // Quoted fields with commas
  const quoted = parseCSV('name,notes\n"Jane","Hello, world"\n"Foo","Bar, Baz"');
  assert(quoted.rows[0].notes === 'Hello, world', 'Quoted fields keep commas');

  // Escaped quotes
  const escaped = parseCSV('quote\n"She said ""Hi"""');
  assert(escaped.rows[0].quote === 'She said "Hi"', 'Escaped quotes');

  // Custom delimiter, quote, and line separator
  const customInput = "name|note; 'Mark'|'multi|value'; 'Jane'|'simple'";
  const custom = parseCSV(customInput, { delimiter: '|', quote: "'", lineSeparator: ';' });
  assert(custom.rows.length === 2, 'Custom parsing row count');
  assert(custom.rows[0].name.trim() === "Mark", 'Custom header trimming not performed on header streaming?');
  assert(custom.rows[0].note === 'multi|value', 'Custom delimiter inside quote');

  // Type coercion (numbers, booleans, nulls, strings)
  const typeInput = ['value', '42', '3.14', 'TRUE', 'false', 'null', '', 'greeting'].join('\n');
  const typeResult = parseCSV(typeInput);
  assert(typeResult.rows.length === 7, 'Type coercion row count');
  assert(typeResult.rows[0].value === 42, 'Integer conversion');
  assert(typeResult.rows[1].value === 3.14, 'Float conversion');
  assert(typeResult.rows[2].value === true, 'True boolean');
  assert(typeResult.rows[3].value === false, 'False boolean');
  assert(typeResult.rows[4].value === null, 'String null');
  assert(typeResult.rows[5].value === null, 'Empty string null conversion');
  assert(typeResult.rows[6].value === 'greeting', 'String stays as string');

  // Malformed row error collection
  const malformed = parseCSV('a,b\n1\n2,3');
  assert(malformed.errors.length === 1, 'Malformed row counted');
  assert(malformed.errors[0].row === 2, 'Malformed row index correct');
  assert(malformed.errors[0].message.includes('Expected 2 columns'), 'Malformed row message');

  // Filter functionality
  const filtering = parseCSV('name,age\nAlice,30\nBob,20\nCarol,40');
  const filtered = filtering.filter(row => (row.age ?? 0) > 25);
  assert(filtered.length === 2, 'Filter returns 2 rows');
  assert(filtered.some(row => row.name === 'Alice'), 'Filter contains specific row');

  // Aggregation methods
  const metrics = parseCSV('category,value\nA,10\nA,20\nB,5\nC,foo');
  assert(metrics.sum('value') === 35, 'Sum ignores non-numeric values');
  const expectedAverage = (10 + 20 + 5) / 3;
  assert(metrics.average('value') !== null && Math.abs(metrics.average('value')! - expectedAverage) < 1e-9, 'Average works');
  assert(metrics.count() === 4, 'Count returns total rows');
  const grouped = metrics.groupBy('category');
  assert(grouped.get('A')?.length === 2, 'Group A has 2 rows');
  assert(grouped.get('B')?.length === 1, 'Group B one row');
  assert(grouped.get('C')?.length === 1, 'Group C one row');

  // Edge cases
  const empty = parseCSV('');
  assert(empty.headers.length === 0, 'Empty input headers');
  assert(empty.rows.length === 0, 'Empty input rows');
  assert(empty.count() === 0, 'Empty input count');

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.rows.length === 1, 'Single column row count');
  assert(singleColumn.rows[0].only === 'value', 'Single column value');

  const headerOnly = parseCSV('a,b');
  assert(headerOnly.rows.length === 0, 'Header only returns zero rows');

  const large = parseCSV(`key,desc\nbig,"${'x'.repeat(5000)}"`);
  assert(large.rows[0].desc.length === 5000, 'Large field preserved');

  console.log('All csv-parser tests passed.');
};

runTests();

