  const basic = parseCSV('name,age\nAlice,30\nBob,25');
  assert(basic.headers.length === 2, 'Basic parsing - header count mismatch');
  assert(basic.rows.length === 2, 'Basic parsing - row count mismatch');
  assert(basic.rows[0].name === 'Alice', 'Basic parsing - first row name');
  assert(basic.rows[0].age === 30, 'Basic parsing - numeric coercion');
  assert(basic.errors.length === 0, 'Basic parsing - unexpected errors');

  // Quoted fields with commas
  const quoted = parseCSV('name,notes\n"Jane","Hello, world"\n"Foo","Bar, Baz"');
  assert(quoted.rows[0].notes === 'Hello, world', 'Quoted field handles commas');

  // Escaped quotes
  const escaped = parseCSV('quote\n"She said ""Hi"""');
  assert(escaped.rows[0].quote === 'She said "Hi"', 'Escaped quotes handled correctly');

  // Custom delimiter, quote, and line separator
  const customInput = "name|note; 'Mark'|'multi|value'; 'Jane'|'simple'";
  const custom = parseCSV(customInput, { delimiter: '|', quote: "'", lineSeparator: ';' });
  assert(custom.rows.length === 2, 'Custom parsing row count');
  assert(custom.rows[0].name === 'Mark', 'Custom parsing respects custom quote/delimiter');
  assert(custom.rows[0].note === 'multi|value', 'Custom delimiter inside quotes preserved');

  // Type coercion (numbers, booleans, nulls, strings)
  const typeInput = ['value', '42', '3.14', 'TRUE', 'false', 'null', 'NULL', '', 'greeting'].join('\n');
  const typeResult = parseCSV(typeInput);
  assert(typeResult.rows.length === 8, 'Type coercion row count mismatch');
  assert(typeResult.rows[0].value === 42, 'Type coercion integer');
  assert(typeResult.rows[1].value === 3.14, 'Type coercion float');
  assert(typeResult.rows[2].value === true, 'Type coercion boolean true');
  assert(typeResult.rows[3].value === false, 'Type coercion boolean false');
  assert(typeResult.rows[4].value === null, 'Type coercion null keyword lower case');
  assert(typeResult.rows[5].value === null, 'Type coercion null keyword upper case');
  assert(typeResult.rows[6].value === null, 'Type coercion empty string');
  assert(typeResult.rows[7].value === 'greeting', 'Type coercion default string');

  // Malformed row error collection
  const malformed = parseCSV('a,b\n1\n2,3');
  assert(malformed.errors.length === 1, 'Malformed row error count');
  assert(malformed.errors[0].row === 2, 'Malformed row number correct');
  assert(malformed.errors[0].message.includes('Expected 2 columns'), 'Malformed row message detail');

  // Filter functionality
  const filtering = parseCSV('name,age\nAlice,30\nBob,20\nCarol,40');
  const filtered = filtering.filter(row => (row.age ?? 0) > 25);
  assert(filtered.length === 2, 'Filter should return two rows');
  assert(filtered.some(row => row.name === 'Alice'), 'Filter retains matching row');

  // Aggregation methods
  const metrics = parseCSV('category,value\nA,10\nA,20\nB,5\nC,foo');
  assert(metrics.sum('value') === 35, 'Sum skips non-numeric entries');
  const expectedAverage = (10 + 20 + 5) / 3;
  assert(metrics.average('value') !== null && Math.abs(metrics.average('value')! - expectedAverage) < 1e-9, 'Average calculation');
  assert(metrics.count() === 4, 'Total row count');
  const grouped = metrics.groupBy('category');
  assert(grouped.get('A')?.length === 2, 'Group A contains two entries');
  assert(grouped.get('B')?.length === 1, 'Group B contains one entry');
  assert(grouped.get('C')?.length === 1, 'Group C contains one entry');

  // Edge cases
  const empty = parseCSV('');
  assert(empty.headers.length === 0, 'Empty input has zero headers');
  assert(empty.rows.length === 0, 'Empty input has zero rows');
  assert(empty.count() === 0, 'Empty input count zero');

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.rows.length === 1, 'Single column row count');
  assert(singleColumn.rows[0].only === 'value', 'Single column value');

  const headerOnly = parseCSV('a,b');
  assert(headerOnly.rows.length === 0, 'Header only results in zero rows');

  const large = parseCSV(`key,desc\nbig,"${'x'.repeat(5000)}"`);
  assert(large.rows[0].desc.length === 5000, 'Large field preserved');

  console.log('All csv-parser tests passed.');
};

runTests();

