export interface ParseOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVRow {
  [header: string]: any;
}

export interface CSVResult {
  headers: string[];
  rows: CSVRow[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  sum(column: string): number;
  average(column: string): number | null;
  count(): number;
  groupBy(column: string): Map<any, CSVRow[]>;
}

interface ParsedRow {
  fields: string[];
  rowNumber: number;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function coerceValue(rawValue: string): any {
  const normalized = rawValue == null ? '' : rawValue.trim();
  if (normalized === '') {
    return null;
  }

  const lower = normalized.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  const numberPattern = /^[+-]?(\d+\.?\d*|\.\d+)$/;
  if (numberPattern.test(normalized)) {
    const parsed = Number(normalized);
    if (!Number.isNaN(parsed)) {
      return parsed;
    }
  }

  return normalized;
}

export function parseCSV(input: string, options: ParseOptions = {}): CSVResult {
  const delimiter = options.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quote = options.quote && options.quote.length > 0 ? options.quote : DEFAULT_QUOTE;
  const lineSeparator = options.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : DEFAULT_LINE_SEPARATOR;
  const customLineSeparator = typeof options.lineSeparator === 'string' && options.lineSeparator.length > 0;

  let workingInput = input ?? '';
  if (!customLineSeparator) {
    workingInput = workingInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  const parsedRows: ParsedRow[] = [];
  const delimiterLength = delimiter.length;
  const lineSeparatorLength = lineSeparator.length;

  let currentRow: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let nextRowNumber = 1;
  let currentRowNumber = nextRowNumber;
  let unterminatedQuoteRow: number | null = null;

  const finalizeField = () => {
    currentRow.push(currentField);
    currentField = '';
  };

  const finalizeRow = () => {
    finalizeField();
    parsedRows.push({ fields: currentRow, rowNumber: currentRowNumber });
    nextRowNumber += 1;
    currentRowNumber = nextRowNumber;
    currentRow = [];
  };

  while (workingInput.length > 0) {
    const chunkStart = 0;
    if (!inQuotes && lineSeparatorLength > 0 && workingInput.startsWith(lineSeparator, chunkStart)) {
      finalizeRow();
      workingInput = workingInput.slice(lineSeparatorLength);
      continue;
    }

    if (!inQuotes && delimiterLength > 0 && workingInput.startsWith(delimiter, chunkStart)) {
      finalizeField();
      workingInput = workingInput.slice(delimiterLength);
      continue;
    }

    const char = workingInput[0];

    if (char === quote) {
      if (inQuotes) {
        const peek = workingInput.length > 1 ? workingInput[1] : '';
        if (peek === quote) {
          currentField += quote;
          workingInput = workingInput.slice(2);
          continue;
        }
        inQuotes = false;
        workingInput = workingInput.slice(1);
        continue;
      }
      inQuotes = true;
      workingInput = workingInput.slice(1);
      continue;
    }

    currentField += char;
    workingInput = workingInput.slice(1);
  }

  const hasPendingData = inQuotes || currentField.length > 0 || currentRow.length > 0;
  if (hasPendingData) {
    const pendingRowNumber = currentRowNumber;
    finalizeRow();
    if (inQuotes) {
      unterminatedQuoteRow = pendingRowNumber;
      inQuotes = false;
    }
  }

  const headers = parsedRows.length > 0 ? parsedRows[0].fields : [];
  const expectedColumns = headers.length;
  const rows: CSVRow[] = [];
  const errors: CSVError[] = [];

  for (let index = 1; index < parsedRows.length; index += 1) {
    const entry = parsedRows[index];
    const { fields, rowNumber: parsedRowNumber } = entry;

    if (fields.length !== expectedColumns) {
      errors.push({
        row: parsedRowNumber,
        message: `Expected ${expectedColumns} columns but got ${fields.length}.`,
      });
      continue;
    }

    const rowObject: CSVRow = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex += 1) {
      const header = headers[columnIndex];
      rowObject[header] = coerceValue(fields[columnIndex] ?? '');
    }
    rows.push(rowObject);
  }

  if (unterminatedQuoteRow !== null) {
    errors.push({
      row: unterminatedQuoteRow,
      message: 'Unterminated quoted field detected.',
    });
  }

  const filter = (predicate: (row: CSVRow) => boolean): CSVRow[] => rows.filter(predicate);

  const sum = (column: string): number => {
    let total = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  };

  const average = (column: string): number | null => {
    let total = 0;
    let count = 0;

    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }

    if (count === 0) {
      return null;
    }

    return total / count;
  };

  const count = (): number => rows.length;

  const groupBy = (column: string): Map<any, CSVRow[]> => {
    const grouped = new Map<any, CSVRow[]>();
    for (const row of rows) {
      const key = row[column];
      if (!grouped.has(key)) {
        grouped.set(key, []);
      }
      grouped.get(key)!.push(row);
    }
    return grouped;
  };

  return {
    headers,
    rows,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy,
  };
}
